import React, { useState, useEffect, useMemo, useCallback } from 'react';
import Select from 'react-select';
import './AddPurchase.css';
import AddMaterial from './AddMaterial';
import AddVendor from './AddVendor';

const AddPurchase = ({ handleAdd, locations, vendors, materials, setMaterials }) => {
  const [showAddMaterialForm, setShowAddMaterialForm] = useState(false);
  const [showAddVendorForm, setShowAddVendorForm] = useState(false);
  const [newPurchase, setNewPurchase] = useState({
    location: '',
    materialid: '',
    materialname: '',
    quantity: '',
    price: '',
    vendor: '',
    vendorname: '',
    width: null,
    lotnumber: '',
  });
  const [showExtras, setShowExtras] = useState(false);

  useEffect(() => {
    const fetchData = async () => {
      if (!newPurchase.materialid) {
        setShowExtras(false);
        setNewPurchase((prevPurchase) => ({
          ...prevPurchase,
          price: '',
          vendor: '',
          vendorname: '',
          materialname: '',
        }));
        return;
      }

      try {
        const [responseChanges, responseList] = await Promise.all([
          fetch(`http://localhost:8081/materialchangesAPI/${newPurchase.materialid}`),
          fetch(`http://localhost:8081/materiallist/${newPurchase.materialid}`),
        ]);
        const [dataChanges, dataList] = await Promise.all([
          responseChanges.json(),
          responseList.json(),
        ]);

        setShowExtras(dataList && dataList.extras === 1);

        const selectedVendor = vendors.find((vendor) => vendor.vendorid === dataChanges?.vendor);
        setNewPurchase((prevPurchase) => ({
          ...prevPurchase,
          price: dataChanges?.price || '',
          vendor: dataChanges?.vendor || '',
          vendorname: selectedVendor ? selectedVendor.name : '',
          materialname: dataList?.name || '',
        }));
      } catch (error) {
        console.error('Error fetching material data:', error);
      }
    };

    fetchData();
  }, [newPurchase.materialid, vendors]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setNewPurchase((prevPurchase) => ({
      ...prevPurchase,
      [name]: value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const selectedVendor = vendors.find((vendor) => vendor.name === newPurchase.vendorname);
    const updatedPurchase = {
      ...newPurchase,
      vendor: selectedVendor ? selectedVendor.vendorid : '',
    };

    try {
      const responseChanges = await fetch(`http://localhost:8081/materialchangesAPI/${newPurchase.materialid}`);
      const dataChanges = await responseChanges.json();

      const hasChanges = dataChanges && (
        dataChanges.price !== newPurchase.price ||
        dataChanges.vendor !== updatedPurchase.vendor
      );

      if (hasChanges) {
        const response = await fetch('http://localhost:8081/materialchangesAPI/', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            material_id: newPurchase.materialid,
            price: newPurchase.price,
            vendor: updatedPurchase.vendor,
          }),
        });

        if (!response.ok) {
          console.error('Failed to create material change:', response);
          return;
        }
      }

      handleAdd(newPurchase);

      setNewPurchase({
        ...initialPurchaseState,
        location: newPurchase.location, // Keep location for convenience
      });
    } catch (error) {
      console.error('Error handling the form submission:', error);
    }
  };

  const handleAddMat = useCallback((newMaterial) => {
    const materialExists = materials.some(
      (material) => material.matid === newMaterial.matid || material.name === newMaterial.name
    );
    if (materialExists) {
      alert('Material ID or name already exists.');
      return;
    }

    fetch('http://localhost:8081/materiallist', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(newMaterial),
    })
      .then((response) => {
        if (response.ok) {
          return response.json();
        } else {
          throw new Error('Error adding material');
        }
      })
      .then(() => {
        setMaterials([...materials, newMaterial]);
        setShowAddMaterialForm(false);
      })
      .catch((error) => {
        console.log('Error adding material:', error);
      });
  }, [materials, setMaterials]);

  const vendorOptions = useMemo(() =>
    vendors.map((vendor) => ({ value: vendor.name, label: vendor.name })),
    [vendors]
  );

  return (
    <div>
      {/* Form and UI elements */}
      {/* ... */}

      {showAddMaterialForm && (
        <div className="add-material-overlay">
          <div className="add-material-popup">
            <span className="close-popup" onClick={() => setShowAddMaterialForm(false)}>
              &times;
            </span>
            <AddMaterial handleAdd={handleAddMat} />
          </div>
        </div>
      )}

      {showAddVendorForm && (
        <div className="add-material-overlay">
          <div className="add-material-popup">
            <span className="close-popup" onClick={() => setShowAddVendorForm(false)}>
              &times;
            </span>
            <AddVendor />
          </div>
        </div>
      )}
    </div>
  );
};

export default AddPurchase;
